script.text:

function active$AdjustDeductablePIT(f) {
  f.add_onResponseComplete(on$AdjustDeductablePIT$ResponseComplete);
  f._controlFocus = f.getItem('loai_tn');
}
function close$AdjustDeductablePIT(f) {try {f.remove_onResponseComplete(on$AdjustDeductablePIT$ResponseComplete)} catch (ex) {}}
function init$AdjustDeductablePIT(f) {
  if (f._action == 'New') {
    f.setItemValues('nam, ma_dvcs, ten_dvcs%l', [f.grid._year, f._unitCode, f._unitName]);
    f.live(f.getItem('loai_tn'));
  }
  f.setReferenceKeyFilter('ma_nv');
}
function onchange$AdjustDeductablePIT$IDNumber(o) {o.parentForm.request('IDNumber', 'IDNumber', ['ma_nv']);}
function on$AdjustDeductablePIT$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'IDNumber':
      f.setItemControlBehavior('stt_rec', result[0].Value, true);
      break;
    default:
      break;
  }
}
